wrong_code:
// WRONG — 0x4e487b71 is Solidity's internal Panic selector
// used by the compiler for divide-by-zero, array OOB etc.
// NEVER use this manually
if lt(senderBalance, amount) {
    mstore(0x00, 0x4e487b71) // Panic(uint256) — WRONG
    revert(0x1c, 0x04)
}

correct_code:
// CORRECT — use keccak256-derived custom error selectors
if lt(senderBalance, amount) {
    mstore(0x00, 0xf4d678b8) // InsufficientBalance()
    revert(0x1c, 0x04)
}

// For allowance checks:
if lt(allowance, amount) {
    mstore(0x00, 0x13be252b) // InsufficientAllowance()
    revert(0x1c, 0x04)
}
